import{_ as i,c as t,a1 as g,o as h}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Sniffing","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/7-sniffing/0-Introduction.md","filePath":"vi/categories/ethical-hacking-labs/7-sniffing/0-Introduction.md"}'),c={name:"vi/categories/ethical-hacking-labs/7-sniffing/0-Introduction.md"};function o(a,n,e,l,r,s){return h(),t("div",null,n[0]||(n[0]=[g('<h1 id="sniffing" tabindex="-1">Sniffing <a class="header-anchor" href="#sniffing" aria-label="Permalink to &quot;Sniffing&quot;">​</a></h1><p>Sniffing là quá trình giám sát và bắt tất cả các gói tin đi qua một mạng nhất định bằng các công cụ sniffing. Đây là một hình thức &quot;nghe trộm đường dây điện thoại&quot; và tìm hiểu về cuộc trò chuyện. Nó còn được gọi là nghe trộm áp dụng cho mạng máy tính.</p><p align="center"><img width="68%" src="https://www.bettercap.org/legacy/assets/img/mitm.jpg"></p><p>Có rất nhiều khả năng rằng nếu một tập hợp các cổng switch doanh nghiệp mở, thì một trong số nhân viên của họ có thể sniff toàn bộ lưu lượng của mạng. Bất kỳ ai ở cùng vị trí vật lý có thể cắm vào mạng bằng cáp Ethernet hoặc kết nối không dây với mạng đó và sniff toàn bộ lưu lượng.</p><h3 id="nhung-gi-co-the-bi-sniff" tabindex="-1">Những gì có thể bị sniff? <a class="header-anchor" href="#nhung-gi-co-the-bi-sniff" aria-label="Permalink to &quot;Những gì có thể bị sniff?&quot;">​</a></h3><ul><li>Lưu lượng email</li><li>Mật khẩu FTP</li><li>Lưu lượng web</li><li>Mật khẩu Telnet</li><li>Cấu hình router</li><li>Phiên trò chuyện</li><li>Lưu lượng DNS</li></ul><h2 id="cac-loai-sniffing" tabindex="-1">Các loại Sniffing <a class="header-anchor" href="#cac-loai-sniffing" aria-label="Permalink to &quot;Các loại Sniffing&quot;">​</a></h2><p><em>Sniffing có thể là <strong>Chủ động (Active)</strong> hoặc <strong>Thụ động (Passive)</strong>.</em></p><h3 id="trong-sniffing-thu-đong" tabindex="-1">Trong sniffing thụ động, <a class="header-anchor" href="#trong-sniffing-thu-đong" aria-label="Permalink to &quot;Trong sniffing thụ động,&quot;">​</a></h3><p>lưu lượng bị theo dõi nhưng không bị thay đổi theo bất kỳ cách nào. Sniffing thụ động chỉ cho phép nghe. Nó hoạt động với thiết bị Hub. Trên thiết bị hub, lưu lượng được gửi đến tất cả các cổng. Trong mạng sử dụng hub để kết nối các hệ thống, tất cả các máy chủ trên mạng có thể thấy lưu lượng. Do đó, kẻ tấn công có thể dễ dàng bắt lưu lượng đi qua.</p><h3 id="trong-sniffing-chu-đong" tabindex="-1">Trong sniffing chủ động, <a class="header-anchor" href="#trong-sniffing-chu-đong" aria-label="Permalink to &quot;Trong sniffing chủ động,&quot;">​</a></h3><p>lưu lượng không chỉ bị theo dõi và giám sát, mà còn có thể bị thay đổi theo cách nào đó được xác định bởi cuộc tấn công. Sniffing chủ động được sử dụng để sniff mạng dựa trên switch. Nó bao gồm việc tiêm các gói phân giải địa chỉ (ARP) vào mạng mục tiêu để tràn bảng CAM (content addressable memory) của switch. CAM theo dõi máy chủ nào được kết nối với cổng nào.</p><p>Một số kỹ thuật Sniffing chủ động:</p><ul><li>MAC Flooding</li><li>Tấn công DHCP</li><li>DNS Poisoning</li><li>Tấn công Spoofing</li><li>ARP Poisoning</li></ul><h2 id="cac-giao-thuc-bi-anh-huong" tabindex="-1">Các giao thức bị ảnh hưởng <a class="header-anchor" href="#cac-giao-thuc-bi-anh-huong" aria-label="Permalink to &quot;Các giao thức bị ảnh hưởng&quot;">​</a></h2><p>Các giao thức như TCP/IP truyền thống không bao giờ được thiết kế với bảo mật trong tâm trí và do đó không cung cấp nhiều khả năng chống lại kẻ xâm nhập tiềm năng. Một số quy tắc dễ bị sniff.</p><ul><li><p><strong>HTTP</strong> − Nó được sử dụng để gửi thông tin dưới dạng plain text mà không có bất kỳ mã hóa nào và do đó là mục tiêu thực sự.</p></li><li><p><strong>SMTP</strong> <em>(Simple Mail Transfer Protocol)</em> − SMTP chủ yếu được sử dụng để chuyển email. Giao thức này hiệu quả, nhưng nó không bao gồm bất kỳ bảo vệ nào chống lại sniffing.</p></li><li><p><strong>NNTP</strong> <em>(Network News Transfer Protocol)</em> − Nó được sử dụng cho tất cả các loại giao tiếp, nhưng nhược điểm chính là dữ liệu và thậm chí mật khẩu được gửi qua mạng dưới dạng plain text.</p></li><li><p><strong>POP</strong> <em>(Post Office Protocol)</em> − POP được sử dụng nghiêm ngặt để nhận email từ server. Giao thức này không bao gồm bảo vệ chống lại sniffing vì nó có thể bị bắt.</p></li><li><p><strong>FTP</strong> <em>(File Transfer Protocol)</em> − FTP được sử dụng để gửi và nhận tệp, nhưng nó không cung cấp bất kỳ tính năng bảo mật nào. Tất cả dữ liệu được gửi dưới dạng plain text có thể dễ dàng bị sniff.</p></li><li><p><strong>IMAP</strong> <em>(Internet Message Access Protocol)</em> − IMAP giống SMTP trong các chức năng, nhưng nó rất dễ bị sniff.</p></li><li><p><strong>Telnet</strong> − Telnet gửi mọi thứ (tên người dùng, mật khẩu, keystrokes) qua mạng dưới dạng plain text và do đó, nó có thể dễ dàng bị sniff.</p></li></ul><p>_Nguồn: <a href="https://www.tutorialspoint.com/ethical_hacking/ethical_hacking_sniffing.htm_" target="_blank" rel="noreferrer">https://www.tutorialspoint.com/ethical_hacking/ethical_hacking_sniffing.htm_</a></p>',18)]))}const m=i(c,[["render",o]]);export{u as __pageData,m as default};
